Consider the following code:

class Animal:
    def __init__(self, name):
        self.name = name

    def speak(self):
        return 'Some sound'

class Dog(Animal):
    def __init__(self, name, breed):
        super().__init__(name)
        self.breed = breed

    def speak(self):
        return 'Woof!'

d = Dog('Max', 'Labrador')
print(d.name, d.breed, d.speak())

What is the output?

