What will the following code print?

class Base:
    def __init__(self):
        print('Base __init__')
        self.value = self.get_value()

    def get_value(self):
        return 10

class Derived(Base):
    def __init__(self):
        print('Derived __init__')
        super().__init__()
        self.value = self.get_value()

    def get_value(self):
        return 20

d = Derived()
print('Value:', d.value)

What is the output of this code involving a singleton pattern using __new__?

class Singleton:
    _instance = None

    def __new__(cls):
        if cls._instance is None:
            cls._instance = super().__new__(cls)
        return cls._instance

    def __init__(self, value):
        self.value = value

s1 = Singleton(10)
s2 = Singleton(20)
print(s1.value, s2.value, s1 is s2)
